// dashboards/claude/golden_signals.jsonnet
local grafana = import 'grafonnet/grafana.libsonnet';
local dashboard = grafana.dashboard;
local graphPanel = grafana.graphPanel;
local prometheus = grafana.target.prometheus;
local template = grafana.template;

local feature = template.new(
  name='feature',
  datasource='$datasource',
  query='label_values(claude_api_request_total, feature)',
  label='Feature',
  refresh='load',
);

local latencyPanel = graphPanel.new(
  title='Request Latency p50 / p99',
  datasource='$datasource',
  legend_rightSide=true,
).addTargets([
  prometheus.target(
    expr='histogram_quantile(0.50, sum by (le) (rate(claude_api_request_duration_seconds_bucket{feature="$feature"}[5m])))',
    legendFormat='p50',
  ),
  prometheus.target(
    expr='histogram_quantile(0.99, sum by (le) (rate(claude_api_request_duration_seconds_bucket{feature="$feature"}[5m])))',
    legendFormat='p99',
  ),
]);

local errorRatePanel = graphPanel.new(
  title='Error Rate by Category',
  datasource='$datasource',
).addTarget(
  prometheus.target(
    expr='sum by (error_category) (rate(claude_api_error_total{feature="$feature"}[5m]))',
    legendFormat='{{ error_category }}',
  )
);

dashboard.new(
  title='Claude Golden Signals',
  uid='claude-golden-signals',
  tags=['claude', 'observability'],
  time_from='now-3h',
  refresh='1m',
  schemaVersion=36,
)
.addTemplate(template.datasource(name='datasource', query='prometheus', label='Datasource'))
.addTemplate(feature)
.addPanels([
  latencyPanel { gridPos: { x: 0, y: 0, w: 12, h: 8 } },
  errorRatePanel { gridPos: { x: 12, y: 0, w: 12, h: 8 } },
])

// dashboards/lib/targets.libsonnet
{
  // Reusable PromQL target builders for standard Claude metrics
  claudeLatencyP99(feature='$feature', range='5m')::
    {
      expr: |||
        histogram_quantile(0.99,
          sum by (le) (
            rate(claude_api_request_duration_seconds_bucket{feature="%(feature)s"}[%(range)s])
          )
        )
      ||| % { feature: feature, range: range },
      legendFormat: 'p99',
      refId: 'A',
    },

  claudeErrorRate(feature='$feature', range='5m')::
    {
      expr: |||
        sum(rate(claude_api_error_total{feature="%(feature)s"}[%(range)s]))
        /
        sum(rate(claude_api_request_total{feature="%(feature)s"}[%(range)s]))
      ||| % { feature: feature, range: range },
      legendFormat: 'error rate',
      refId: 'B',
    },

  claudeTokenRate(feature='$feature', type='input', range='5m')::
    {
      expr: |||
        sum(rate(claude_tokens_total{feature="%(feature)s",token_type="%(type)s"}[%(range)s]))
      ||| % { feature: feature, type: type, range: range },
      legendFormat: '%(type)s tokens/s' % { type: type },
      refId: 'C',
    },
}

# tests/test_dashboards.py
import json, glob, pytest

RENDERED_DIR = "dashboards/rendered"


@pytest.fixture(params=glob.glob(f"{RENDERED_DIR}/**/*.json", recursive=True))
def dashboard(request):
    with open(request.param) as f:
        return json.load(f), request.param


def test_has_uid(dashboard):
    data, path = dashboard
    assert data.get("uid"), f"{path}: missing uid"


def test_is_not_editable(dashboard):
    data, path = dashboard
    assert data.get("editable") is False, f"{path}: dashboard must be non-editable"


def test_has_at_least_one_panel(dashboard):
    data, path = dashboard
    assert len(data.get("panels", [])) >= 1, f"{path}: no panels"


def test_no_empty_queries(dashboard):
    data, path = dashboard
    for panel in data.get("panels", []):
        for target in panel.get("targets", []):
            assert target.get("expr", "").strip(), (
                f"{path}: panel '{panel.get('title')}' has an empty PromQL expression"
            )


def test_refresh_interval_set(dashboard):
    data, path = dashboard
    assert data.get("refresh"), f"{path}: refresh interval not set"
